<template>
    <view class="con">
        <view class="time">
            <view class="timeItem" v-for="(item,index) in times">
                <view class="timeName" v-text="item.time"></view>
                <view class="point"></view>
            </view>
        </view>
        <view class="manager">
            <view class="mItem" v-for="(item,index) in managers">
                <view class="mTop">
                    <view class="pe" v-text="item.name"></view>
                    <view class="pecolor" :style="`background:${item.color}`"></view>
                </view>
                <view class="mContent">
                    <view class="dateItem" v-for="(ite,idx) in item.times" :style="format(ite.color)"
                        @click="addThis(ite)">
                        <view class="itemName" :style="`color:${ite.color}`">
                            <view class="bd" v-if="ite.start" :style="`background:${ite.color}`"></view>
                            {{ite.name}}
                        </view>
                        <view class="itemEvent" :style="`color:${ite.color}`">
                            {{ite.event}}
                        </view>
                    </view>
                </view>
            </view>
        </view>
    </view>
</template>

<script>
    export default {
        name: "progres",
        props: ['times', 'manager'],
        data() {
            return {
                managers: []
            };
        },
        mounted() {

        },
        watch: {
            times: function(newVal, oldVal) {
                this.times = newVal; //newVal即是chartData
            },
            manager: function(newVal, oldVal) {
                let array = JSON.parse(JSON.stringify(newVal));
                for (let i = 0; i < array.length; i++) {
                    for (let j = 0; j < array[i].events.length; j++) {
                        let start
                        for (let k = 0; k < array[i].times.length; k++) {
                            if (array[i].times[k].time == array[i].events[j].start) {
                                array[i].times[k].start = true
                                array[i].times[k].checked = true
                                array[i].times[k].name = array[i].events[j].name
                                array[i].times[k].event = array[i].events[j].event
                                array[i].times[k].color = array[i].color
                                start = k
                            } else {
                                if (k > start && k < start + (array[i].events[j].duration) * 2) {
                                    array[i].times[k].checked = true
                                    array[i].times[k].color = array[i].color
                                } else {
                                    array[i].times[k].checked = false
                                }
                            }
                        }
                    }
                }
                this.managers = array
            }
        },
        created() {},
        methods: {
            format(e) {
                if (e) {
                    let color = e.replace(")", ",0.2)")
                    let final = color.replace("rgb", "rgba")
                    return "background:" + final + ";border-bottom:2upx solid " + final
                }
            },
            addThis(e) {
                let that = this
                if (e.checked == true || e.start == true) {
                    uni.showToast({
                        title: "不接受预约",
                        icon: "none"
                    })
                } else {
                    this.$emit("addNew", 123)
                }

            }
        }
    }
</script>

<style lang="scss">
    .con {
        width: 750upx;
        display: flex;

        .time {
            box-sizing: border-box;
            padding: 100upx 0 0 30upx;
            position: relative;
            top: -40upx;

            .timeItem {
                height: 80upx;
                font-size: 24upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
                width: 130upx;
                line-height: 80upx;
                display: flex;
                align-items: center;
                justify-content: space-between;
                text-align: center;

                .timeName {
                    flex: 1;
                    text-align: center;
                }

                .point {
                    width: 20upx;
                    height: 2upx;
                    background-color: #EAEAEA;
                }
            }
        }
    }

    .manager {
        width: 560upx;
        overflow-x: scroll;
        display: flex;
        border-top: none;
        border-left: 2upx solid #EAEAEA;

        .mItem {
            width: 140upx;
            flex-shrink: 0;
            box-sizing: border-box;
            padding: 0;
            position: relative;

            .mContent {
                width: 100%;
                border-top: 2upx solid #eaeaee;
                position: relative;

                .dateItem {
                    width: 100%;
                    height: 80upx;
                    box-sizing: border-box;
                    border: 2upx solid #EAEAEA;
                    border-left: none;
                    border-top: none;
                    font-size: 24upx;
                    font-family: Hiragino Sans-W5, Hiragino Sans;
                    font-weight: normal;

                    .itemName {
                        box-sizing: border-box;
                        position: relative;
                        padding: 16upx 8upx 0;

                        .bd {
                            width: 100%;
                            height: 8upx;
                            border-radius: 8upx;
                            position: absolute;
                            top: 0;
                            left: 0;
                        }
                    }

                    .itemEvent {
                        box-sizing: border-box;
                        padding: 0 8upx;
                    }
                }
            }

            .mTop {
                height: 100upx;
                display: flex;
                flex-direction: column;
                justify-content: center;
                align-items: center;
                position: sticky;
                top: 0;
                left: 0;

                .pe {
                    width: 100%;
                    text-align: center;
                    font-size: 24upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #86868B;
                    margin-bottom: 6upx;

                }

                .pecolor {
                    width: 128upx;
                    height: 8upx;
                    border-radius: 8upx;
                    margin: 0 auto;
                    position: absolute;
                    bottom: 16upx;
                    left: 6upx;
                }
            }
        }

    }
</style>
